import { getBlogPosts } from "../../lib/blog-api";
function escapeXml(value:string){return value.replace(/[<>&'\"]/g,(char)=>({"<":"&lt;",">":"&gt;","&":"&amp;","'":"&apos;",'"':"&quot;"}[char]||char));}
export async function GET(){const site=process.env.NEXT_PUBLIC_SITE_URL||"https://www.summflux.com";const {data:posts}=await getBlogPosts({limit:24});const items=posts.map((post)=>`<item><title>${escapeXml(post.title)}</title><link>${site}/blog/${post.slug}</link><guid>${site}/blog/${post.slug}</guid><description>${escapeXml(post.excerpt)}</description><pubDate>${new Date(post.published_at).toUTCString()}</pubDate></item>`).join("");const xml=`<?xml version="1.0" encoding="UTF-8"?><rss version="2.0"><channel><title>Blog SummFlux</title><link>${site}/blog</link><description>Inteligência comercial, vendas, WhatsApp e CRM.</description>${items}</channel></rss>`;return new Response(xml,{headers:{"content-type":"application/rss+xml; charset=utf-8","cache-control":"public, s-maxage=300, stale-while-revalidate=600"}})}
